const BACKUP_ROOT = path.join(ROOT, "backups", "v19_megalayout_2026_" + new Date().toISOString().replace(/[:.]/g, "-").replace("T", "_").slice(0, 19));

const FILES = {"room_html": "<!doctype html>\n<html lang=\"pt-BR\">\n<head>\n  <meta charset=\"utf-8\" />\n  <meta http-equiv=\"Content-Security-Policy\" content=\"default-src 'self' file: data: blob:; img-src 'self' file: data: blob:; style-src 'self' 'unsafe-inline'; script-src 'self'; connect-src 'self' http://127.0.0.1:* http://localhost:* file: blob: data:;\" />\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1\" />\n  <title>Noelle Room V19</title>\n  <link rel=\"stylesheet\" href=\"./styles/room_v19.css\" />\n</head>\n<body>\n  <div id=\"roomV19\" class=\"room-shell\">\n    <header class=\"room-topbar\">\n      <div class=\"brand\">\n        <span class=\"brand-mark\">♛</span>\n        <div>\n          <strong>Noelle Room V19</strong>\n          <small>Build · Yoru POV · Third Person · Roadmap 100</small>\n        </div>\n      </div>\n\n      <nav class=\"mode-tabs\" aria-label=\"Modos da Room\">\n        <button id=\"modeBuild\" class=\"mode active\">Build</button>\n        <button id=\"modePov\" class=\"mode\">Yoru POV</button>\n        <button id=\"modeThird\" class=\"mode\">Third Person</button>\n        <button id=\"btnJump\" class=\"mode\">Pular</button>\n        <button id=\"btnFreeMove\" class=\"mode\">Parar foco</button>\n      </nav>\n\n      <div class=\"top-actions\">\n        <button id=\"btnSave\">Salvar</button>\n        <button id=\"btnLoad\">Carregar</button>\n        <button id=\"btnRecover\">Autosave</button>\n      </div>\n    </header>\n\n    <aside class=\"room-leftbar\">\n      <section class=\"panel compact\">\n        <h2>Ferramentas</h2>\n        <div class=\"tool-grid\">\n          <button id=\"toolMove\">Mover</button>\n          <button id=\"toolRotate\">Girar</button>\n          <button id=\"toolScale\">Escalar</button>\n          <button id=\"toolGrid\">Grid</button>\n          <button id=\"toolUndo\">Undo</button>\n          <button id=\"toolRedo\">Redo</button>\n          <button id=\"toolResetPlayer\">Reset Yoru</button>\n          <button id=\"toolDefaultCamera\">Reset câmera</button>\n        </div>\n      </section>\n\n      <section class=\"panel grow\">\n        <h2>Assets da Room</h2>\n        <input id=\"assetSearch\" class=\"field\" placeholder=\"Buscar GLB/VRM/item...\" />\n        <select id=\"assetFilter\" class=\"field\">\n          <option value=\"all\">Tudo</option>\n          <option value=\"furniture\">Móveis</option>\n          <option value=\"decor\">Decoração</option>\n          <option value=\"electronics\">Eletrônicos</option>\n          <option value=\"table_prop\">Mesa</option>\n          <option value=\"avatar\">Avatar</option>\n        </select>\n        <div id=\"assetList\" class=\"scroll-list\"></div>\n      </section>\n    </aside>\n\n    <main class=\"room-stage\">\n      <canvas id=\"roomCanvas\"></canvas>\n      <div id=\"hudMode\" class=\"hud mode-hud\">Build</div>\n      <div id=\"hudHelp\" class=\"hud help-hud\">\n        Build: arraste o gizmo · Yoru POV/Third: WASD anda · mouse olha · Espaço pula · Esc libera mouse.\n      </div>\n      <div id=\"toast\" class=\"toast\"></div>\n    </main>\n\n    <aside class=\"room-rightbar\">\n      <section class=\"panel\">\n        <h2>Status</h2>\n        <div id=\"statusBox\" class=\"status-box\">Inicializando Room...</div>\n      </section>\n\n      <section class=\"panel\">\n        <h2>Selecionado</h2>\n        <div id=\"selectedBox\" class=\"status-box muted\">Nenhum objeto selecionado.</div>\n        <div class=\"tool-grid\">\n          <button id=\"btnDuplicate\">Duplicar</button>\n          <button id=\"btnLock\">Travar</button>\n          <button id=\"btnGround\">Chão</button>\n          <button id=\"btnRemove\" class=\"danger\">Remover</button>\n        </div>\n      </section>\n\n      <section class=\"panel grow\">\n        <h2>Roadmap 100</h2>\n        <input id=\"roadmapSearch\" class=\"field\" placeholder=\"Buscar sugestão...\" />\n        <div id=\"roadmapList\" class=\"scroll-list roadmap-list\"></div>\n      </section>\n    </aside>\n\n    <footer class=\"room-downbar\">\n      <span id=\"downMode\">Modo: Build</span>\n      <span id=\"downPlayer\">Yoru: 0,0,0</span>\n      <span id=\"downAsset\">Asset: aguardando</span>\n      <span id=\"downSave\">Autosave: pronto</span>\n    </footer>\n  </div>\n\n  <script src=\"./renderer_dist/room.bundle.js\"></script>\n</body>\n</html>\n", "room_css": ":root {\n  --bg: #070711;\n  --panel: rgba(17, 15, 29, 0.94);\n  --panel2: rgba(32, 23, 42, 0.92);\n  --line: rgba(255, 83, 136, 0.26);\n  --text: #fff4fb;\n  --muted: #bcaec7;\n  --accent: #ff477e;\n  --accent2: #8b5cf6;\n  --ok: #41f2ad;\n  --warn: #ffd166;\n  --bad: #ff667a;\n  --bar: 68px;\n  --down: 34px;\n  --left: clamp(248px, 20vw, 320px);\n  --right: clamp(260px, 22vw, 360px);\n}\n\n* { box-sizing: border-box; }\nhtml, body { width: 100%; height: 100%; margin: 0; overflow: hidden; }\nbody {\n  font-family: Inter, \"Segoe UI\", system-ui, sans-serif;\n  color: var(--text);\n  background: radial-gradient(circle at 20% 0%, rgba(139,92,246,.25), transparent 34%), var(--bg);\n}\n\n.room-shell {\n  display: grid;\n  grid-template-columns: var(--left) minmax(420px, 1fr) var(--right);\n  grid-template-rows: var(--bar) minmax(0, 1fr) var(--down);\n  width: 100vw;\n  height: 100vh;\n}\n\n.room-topbar {\n  grid-column: 1 / -1;\n  grid-row: 1;\n  display: grid;\n  grid-template-columns: minmax(220px, 340px) 1fr auto;\n  align-items: center;\n  gap: 12px;\n  padding: 10px 14px;\n  border-bottom: 1px solid var(--line);\n  background: rgba(9, 7, 17, .96);\n  min-width: 0;\n}\n\n.brand { display: flex; align-items: center; gap: 10px; min-width: 0; }\n.brand-mark {\n  width: 40px; height: 40px;\n  display: grid; place-items: center;\n  border-radius: 16px;\n  background: linear-gradient(135deg, var(--accent), var(--accent2));\n  box-shadow: 0 0 30px rgba(255,71,126,.25);\n}\n.brand strong { display: block; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n.brand small { display: block; color: var(--muted); font-size: 12px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }\n\n.mode-tabs, .top-actions, .tool-grid {\n  display: flex;\n  gap: 8px;\n  flex-wrap: wrap;\n  align-items: center;\n}\n\n.mode-tabs { justify-content: center; }\n.top-actions { justify-content: flex-end; }\n\nbutton, .field {\n  border: 1px solid rgba(255,255,255,.14);\n  color: var(--text);\n  background: rgba(255,255,255,.07);\n  border-radius: 12px;\n  padding: 8px 10px;\n  font-weight: 700;\n  outline: none;\n}\nbutton { cursor: pointer; }\nbutton:hover { border-color: rgba(255,71,126,.55); }\nbutton.active, button.primary {\n  background: linear-gradient(135deg, rgba(255,71,126,.95), rgba(139,92,246,.95));\n  border-color: rgba(255,255,255,.22);\n}\nbutton.danger { border-color: rgba(255,102,122,.42); color: #ffd9df; }\nbutton:disabled { opacity: .45; cursor: not-allowed; }\n\n.room-leftbar, .room-rightbar {\n  min-height: 0;\n  overflow: hidden;\n  padding: 10px;\n  display: flex;\n  flex-direction: column;\n  gap: 10px;\n  background: rgba(5,4,11,.46);\n}\n.room-leftbar { grid-column: 1; grid-row: 2; border-right: 1px solid var(--line); }\n.room-rightbar { grid-column: 3; grid-row: 2; border-left: 1px solid var(--line); }\n\n.panel {\n  border: 1px solid var(--line);\n  background: var(--panel);\n  border-radius: 18px;\n  padding: 12px;\n  min-height: 0;\n  box-shadow: 0 18px 48px rgba(0,0,0,.20);\n}\n.panel.grow { flex: 1; display: flex; flex-direction: column; }\n.panel.compact { flex: 0 0 auto; }\n.panel h2 { margin: 0 0 10px; font-size: 15px; }\n\n.field { width: 100%; margin-bottom: 8px; font-weight: 600; }\n\n.scroll-list {\n  flex: 1;\n  min-height: 0;\n  overflow: auto;\n  display: grid;\n  align-content: start;\n  gap: 8px;\n  padding-right: 2px;\n}\n.item-card, .roadmap-card {\n  border: 1px solid rgba(255,255,255,.10);\n  background: var(--panel2);\n  border-radius: 14px;\n  padding: 10px;\n}\n.item-card strong, .roadmap-card strong { display: block; font-size: 13px; }\n.item-card small, .roadmap-card small { color: var(--muted); display: block; margin: 4px 0 8px; overflow-wrap: anywhere; }\n.roadmap-card { border-left: 3px solid rgba(255,71,126,.55); }\n\n.room-stage {\n  grid-column: 2;\n  grid-row: 2;\n  position: relative;\n  min-height: 0;\n  overflow: hidden;\n  background: #090a14;\n}\n#roomCanvas { width: 100%; height: 100%; display: block; }\n\n.hud {\n  position: absolute;\n  border: 1px solid rgba(255,255,255,.12);\n  border-radius: 14px;\n  background: rgba(7,7,17,.72);\n  backdrop-filter: blur(10px);\n  color: var(--muted);\n  padding: 9px 12px;\n  font-size: 12px;\n  pointer-events: none;\n}\n.mode-hud { top: 12px; left: 12px; color: var(--ok); }\n.help-hud { bottom: 12px; left: 12px; right: 12px; }\n\n.toast {\n  position: absolute;\n  top: 12px;\n  left: 50%;\n  transform: translateX(-50%);\n  opacity: 0;\n  pointer-events: none;\n  transition: opacity .18s ease;\n  border: 1px solid var(--line);\n  background: rgba(17,15,29,.92);\n  border-radius: 999px;\n  padding: 10px 14px;\n}\n.toast.show { opacity: 1; }\n\n.status-box {\n  color: var(--ok);\n  background: rgba(255,255,255,.05);\n  border: 1px solid rgba(255,255,255,.10);\n  border-radius: 14px;\n  padding: 10px;\n  font-size: 13px;\n  line-height: 1.45;\n}\n.status-box.muted { color: var(--muted); }\n\n.room-downbar {\n  grid-column: 1 / -1;\n  grid-row: 3;\n  display: flex;\n  gap: 18px;\n  align-items: center;\n  padding: 0 12px;\n  border-top: 1px solid var(--line);\n  background: rgba(9, 7, 17, .98);\n  color: var(--muted);\n  font-size: 12px;\n  white-space: nowrap;\n  overflow: hidden;\n}\n.room-downbar span { overflow: hidden; text-overflow: ellipsis; }\n\n@media (max-width: 1100px) {\n  .room-shell {\n    grid-template-columns: 260px minmax(320px, 1fr);\n    grid-template-rows: var(--bar) minmax(0, 1fr) 260px var(--down);\n  }\n  .room-rightbar {\n    grid-column: 1 / -1;\n    grid-row: 3;\n    border-left: 0;\n    border-top: 1px solid var(--line);\n    flex-direction: row;\n  }\n  .room-stage { grid-column: 2; grid-row: 2; }\n  .room-downbar { grid-row: 4; }\n}\n\n@media (max-width: 820px) {\n  .room-shell {\n    grid-template-columns: 1fr;\n    grid-template-rows: auto 240px minmax(320px, 1fr) 240px var(--down);\n  }\n  .room-topbar { grid-template-columns: 1fr; grid-row: 1; }\n  .mode-tabs { justify-content: flex-start; }\n  .room-leftbar { grid-column: 1; grid-row: 2; border-right: 0; border-bottom: 1px solid var(--line); }\n  .room-stage { grid-column: 1; grid-row: 3; }\n  .room-rightbar { grid-column: 1; grid-row: 4; }\n  .room-downbar { grid-row: 5; }\n}\n", "room_app": "\"use strict\";\n\nimport * as THREE from \"three\";\nimport { GLTFLoader } from \"three/examples/jsm/loaders/GLTFLoader.js\";\nimport { OrbitControls } from \"three/examples/jsm/controls/OrbitControls.js\";\nimport { TransformControls } from \"three/examples/jsm/controls/TransformControls.js\";\nimport { VRMLoaderPlugin, VRMUtils } from \"@pixiv/three-vrm\";\n\nconst ROADMAP = [\n  \"Confirmar que a Yoru aparece como player real no Third Person, não apenas fallback.\",\n  \"Diagnóstico visual dentro da Room mostrando VRM carregado, fallback, erro de asset e caminho usado.\",\n  \"Melhorar carregamento do Yoru.vrm com log claro de sucesso/falha.\",\n  \"Painel de debug da Room com FPS, modo atual, posição do player, câmera e asset carregado.\",\n  \"Botão Parar foco sempre soltar gizmo e seleção do item.\",\n  \"Evitar conflito ao trocar rápido entre Build Mode, Yoru POV e Third Person.\",\n  \"Câmera Third Person com colisão para não atravessar parede/mesa/piano/objetos grandes.\",\n  \"Ajustar altura dos olhos no Yoru POV por VRM, com fallback configurável.\",\n  \"Botão Recentrar player separado de reset total.\",\n  \"Salvar posição do player corretamente no layout da Room.\",\n  \"Salvar modo atual opcionalmente: Build, Yoru POV ou Third Person.\",\n  \"Melhorar colisão do player com móveis grandes.\",\n  \"Impedir player nascer dentro de objeto depois de carregar layout.\",\n  \"Adicionar chão sólido real para pulo não atravessar ou flutuar.\",\n  \"Melhorar pulo com suavidade, queda natural e limite de spam.\",\n  \"Sistema de paredes da Room em vez de só chão aberto.\",\n  \"Presets reais de quarto: gamer, escritório, musical e simples.\",\n  \"Separar itens de cenário de itens de mão de forma rígida.\",\n  \"Categorias melhores para items: chão, mesa, parede, mão, decoração, eletrônico, instrumento.\",\n  \"Preview do item antes de colocar na Room.\",\n  \"Snap no chão, mesa e parede dependendo do tipo do item.\",\n  \"Pontos de encaixe para mesa: copo, notebook, dado, papel, celular.\",\n  \"Pontos de encaixe para mão/avatar separados da Room.\",\n  \"Impedir item pequeno cair no chão quando deveria ir para mesa.\",\n  \"Botão Mandar para frente da Yoru.\",\n  \"Botão Colocar na mesa mais próxima.\",\n  \"Botão Alinhar com chão melhorado.\",\n  \"Botão Duplicar em grade.\",\n  \"Autosave com várias versões recuperáveis.\",\n  \"Botão Restaurar layout padrão.\",\n  \"Animação idle no Third Person.\",\n  \"Animação walk quando anda.\",\n  \"Animação jump quando pula.\",\n  \"Animação run quando segura Shift.\",\n  \"Sincronizar emotes da Yoru com player da Room.\",\n  \"Sincronizar expressions PNG/VRM com player da Room.\",\n  \"Permitir escolher avatar player: Yoru, Noelle ou outro VRM.\",\n  \"Calibração de altura do avatar.\",\n  \"Opção Mostrar corpo no Yoru POV para debug.\",\n  \"Braços/mãos visíveis no First Person estilo VRChat.\",\n  \"Unificar scripts V18.7, V18.8 e V18.9 para não acumular hotfix.\",\n  \"Criar room_core.js separando player, câmera, layout e UI.\",\n  \"Testes automáticos básicos para Room abrir, bundle gerar e assets existirem.\",\n  \"Diagnóstico para imports de Three.js e @pixiv/three-vrm.\",\n  \"Evitar duplicar handlers de botão quando aplica patch várias vezes.\",\n  \"Garantir só um INICIAR.bat na raiz.\",\n  \"Logs claros no terminal por etapa.\",\n  \"MEMORIA_GPT_NOELLE.md atualizada após cada versão.\",\n  \"Checklist de release: node check, bundle, assets, bat, package, memória.\",\n  \"V19 consolidada limpa, sem restos de hotfix antigo.\",\n  \"Tela Room Status dentro da Room.\",\n  \"Indicador visual do modo atual no canto da tela.\",\n  \"Mini tutorial dentro da Room com controles básicos.\",\n  \"Botão Reset câmera separado do Parar foco.\",\n  \"Reset player mais seguro, voltando para spawn livre.\",\n  \"Spawn point editável para escolher onde a Yoru nasce.\",\n  \"Item invisível Player Spawn no Build Mode.\",\n  \"Proteção contra spawn dentro de parede/móvel.\",\n  \"Sistema de paredes com colisão real.\",\n  \"Teto opcional para Room fechada.\",\n  \"Modo quarto aberto e quarto fechado.\",\n  \"Luz ambiente configurável: claro, escuro, noite, neon, gamer.\",\n  \"Slider de intensidade da luz.\",\n  \"Botão Centralizar Room.\",\n  \"Grid configurável: 0.1, 0.25, 0.5, 1.0.\",\n  \"Snap toggle por eixo: X, Y, Z.\",\n  \"Rotação com snap configurável: 5°, 15°, 30°, 45°, 90°.\",\n  \"Botão Desfazer seleção além do Parar foco.\",\n  \"Outline melhor no item selecionado.\",\n  \"Highlight ao passar mouse sobre item.\",\n  \"Painel de propriedades por item com nome, categoria, posição, rotação, escala e colisão.\",\n  \"Permitir renomear itens colocados na Room.\",\n  \"Permitir travar/destravar item individualmente.\",\n  \"Permitir esconder/mostrar item sem apagar.\",\n  \"Camadas: cenário, móveis, decoração, interativos.\",\n  \"Filtro somente itens visíveis no layout list.\",\n  \"Busca no layout list.\",\n  \"Selecionar item na lista e olhar para ele somente em Build.\",\n  \"Modo câmera livre sem selecionar objeto.\",\n  \"Modo espectador/freecam separado da Yoru POV.\",\n  \"Controle de velocidade da câmera livre.\",\n  \"Controle de velocidade da Yoru.\",\n  \"Controle de altura da câmera do Yoru POV.\",\n  \"Controle de distância da câmera Third Person.\",\n  \"Controle de suavidade da câmera Third Person.\",\n  \"Colisão da câmera com paredes e objetos grandes mais precisa.\",\n  \"Botão Teleportar Yoru para cá clicando no chão.\",\n  \"Botão Trazer Yoru para frente da câmera.\",\n  \"Botão Olhar para item selecionado sem travar foco permanentemente.\",\n  \"Interação básica com objetos: sentar, tocar piano, pegar item, beber água.\",\n  \"Tags de interação no manifesto: sit, drink, play_music, hold, inspect.\",\n  \"Hotspots nos móveis: cadeira tem ponto de sentar, mesa tem ponto de colocar item.\",\n  \"Lógica item de mão + emoção, por exemplo ação de beber usa item correto.\",\n  \"Presets de ação: beber água, usar celular, sentar, tocar piano.\",\n  \"Estados da Yoru por modo: idle, walk, run, jump, sit, interact.\",\n  \"Transição suave entre animações.\",\n  \"Fallback de animação se VRMA não existir.\",\n  \"animation_manifest.json separado ligando animações a ações.\",\n  \"interaction_manifest.json ligando itens a ações possíveis.\",\n  \"V19 como versão consolidada, removendo restos de hotfix e deixando Room/Yoru como sistema principal estável.\"\n];\n\nconst $ = (id) => document.getElementById(id);\nconst api = () => window.noelleRoom || window.noelleRoomV19 || null;\n\nlet renderer, scene, camera, orbit, transform, roomRoot, player, yoruVisual;\nlet mode = \"build\";\nlet selected = null;\nlet placed = new Map();\nlet catalog = [];\nlet history = [];\nlet historyIndex = -1;\nlet keys = new Set();\nlet pointerLocked = false;\nlet playerState = {\n  pos: new THREE.Vector3(0, 0, 2.6),\n  yaw: 0,\n  pitch: 0,\n  velocityY: 0,\n  grounded: true,\n  speed: 2.3,\n  runSpeed: 4.2,\n  radius: 0.28,\n  eyeHeight: 1.50,\n  avatarHeight: 1.62\n};\nlet lastFrame = performance.now();\n\nfunction toast(text) {\n  const el = $(\"toast\");\n  if (!el) return;\n  el.textContent = text;\n  el.classList.add(\"show\");\n  clearTimeout(toast._t);\n  toast._t = setTimeout(() => el.classList.remove(\"show\"), 2200);\n}\n\nfunction status(text, kind = \"ok\") {\n  const box = $(\"statusBox\");\n  if (box) {\n    box.textContent = text;\n    box.style.color = kind === \"bad\" ? \"var(--bad)\" : kind === \"warn\" ? \"var(--warn)\" : \"var(--ok)\";\n  }\n  const asset = $(\"downAsset\");\n  if (asset) asset.textContent = \"Asset: \" + text;\n}\n\nfunction setMode(next) {\n  mode = [\"build\", \"pov\", \"third\"].includes(next) ? next : \"build\";\n  for (const [id, value] of Object.entries({ modeBuild: \"build\", modePov: \"pov\", modeThird: \"third\" })) {\n    $(id)?.classList.toggle(\"active\", value === mode);\n  }\n  $(\"hudMode\").textContent = mode === \"build\" ? \"Build\" : mode === \"pov\" ? \"Yoru POV\" : \"Third Person\";\n  $(\"downMode\").textContent = \"Modo: \" + $(\"hudMode\").textContent;\n\n  const build = mode === \"build\";\n  orbit.enabled = build;\n  transform.enabled = build;\n  if (transform.getHelper) transform.getHelper().visible = build;\n  if (!build) transform.detach();\n\n  if (player) player.visible = mode === \"third\";\n  if (yoruVisual) yoruVisual.visible = mode === \"third\";\n\n  if (mode !== \"build\") requestPointer();\n  if (mode === \"build\") unlockPointer();\n  toast($(\"hudMode\").textContent);\n}\n\nfunction initScene() {\n  const canvas = $(\"roomCanvas\");\n  renderer = new THREE.WebGLRenderer({ canvas, antialias: true });\n  renderer.setPixelRatio(Math.min(devicePixelRatio || 1, 2));\n  renderer.outputColorSpace = THREE.SRGBColorSpace;\n  renderer.shadowMap.enabled = true;\n\n  scene = new THREE.Scene();\n  scene.background = new THREE.Color(0x090a14);\n\n  camera = new THREE.PerspectiveCamera(50, 1, 0.05, 160);\n  camera.position.set(4.5, 3.2, 5.2);\n\n  orbit = new OrbitControls(camera, renderer.domElement);\n  orbit.enableDamping = true;\n  orbit.target.set(0, 0.8, 0);\n\n  transform = new TransformControls(camera, renderer.domElement);\n  transform.setMode(\"translate\");\n  transform.setTranslationSnap(0.25);\n  transform.setRotationSnap(THREE.MathUtils.degToRad(15));\n  transform.setScaleSnap(0.05);\n  scene.add(transform.getHelper ? transform.getHelper() : transform);\n\n  transform.addEventListener(\"dragging-changed\", (event) => {\n    orbit.enabled = !event.value && mode === \"build\";\n  });\n  transform.addEventListener(\"objectChange\", () => {\n    renderSelected();\n    scheduleAutosave();\n  });\n  transform.addEventListener(\"mouseUp\", () => commitHistory());\n\n  scene.add(new THREE.HemisphereLight(0xffffff, 0x171020, 1.8));\n  const light = new THREE.DirectionalLight(0xffffff, 2.0);\n  light.position.set(4, 6, 5);\n  light.castShadow = true;\n  scene.add(light);\n\n  const floor = new THREE.Mesh(\n    new THREE.PlaneGeometry(10, 10),\n    new THREE.MeshStandardMaterial({ color: 0x171420, roughness: 0.9 })\n  );\n  floor.rotation.x = -Math.PI / 2;\n  floor.receiveShadow = true;\n  floor.name = \"Room Floor\";\n  scene.add(floor);\n  scene.add(new THREE.GridHelper(10, 40, 0xff477e, 0x3b3147));\n\n  roomRoot = new THREE.Group();\n  scene.add(roomRoot);\n\n  player = new THREE.Group();\n  scene.add(player);\n  player.visible = false;\n  makeFallbackPlayer();\n\n  window.addEventListener(\"resize\", resize);\n  resize();\n  renderer.domElement.addEventListener(\"pointerdown\", pickObject);\n  animate();\n}\n\nfunction makeFallbackPlayer() {\n  yoruVisual?.removeFromParent?.();\n  yoruVisual = new THREE.Group();\n  const bodyGeom = typeof THREE.CapsuleGeometry === \"function\" ? new THREE.CapsuleGeometry(0.22, 0.75, 6, 12) : new THREE.CylinderGeometry(0.22, 0.22, 1.2, 16);\n  const body = new THREE.Mesh(bodyGeom, new THREE.MeshStandardMaterial({ color: 0xff477e, roughness: 0.65 }));\n  body.position.y = 0.78;\n  const head = new THREE.Mesh(new THREE.SphereGeometry(0.17, 16, 12), new THREE.MeshStandardMaterial({ color: 0xffc1d5 }));\n  head.position.y = 1.45;\n  yoruVisual.add(body, head);\n  player.add(yoruVisual);\n}\n\nasync function loadYoruPlayer() {\n  const urls = [\"./assets/avatars/Yoru.vrm\", \"./assets/Yoru.vrm\", \"./assets/Noelle.vrm\", \"./assets/avatars/Noelle.vrm\"];\n  const loader = new GLTFLoader();\n  loader.register((parser) => new VRMLoaderPlugin(parser));\n  for (const url of urls) {\n    try {\n      const gltf = await loader.loadAsync(url);\n      const vrm = gltf.userData?.vrm;\n      const root = vrm?.scene || gltf.scene;\n      if (!root) throw new Error(\"sem scene\");\n      try { VRMUtils.rotateVRM0?.(vrm); } catch {}\n      const wrap = new THREE.Group();\n      wrap.add(root);\n      normalizeObject(wrap, 1.62);\n      yoruVisual.removeFromParent();\n      yoruVisual = wrap;\n      player.add(yoruVisual);\n      playerState.eyeHeight = 1.50;\n      status(\"Yoru player carregada: \" + url, \"ok\");\n      return;\n    } catch (err) {\n      console.warn(\"Falha ao carregar player\", url, err);\n    }\n  }\n  status(\"Yoru.vrm não carregou; fallback visível\", \"warn\");\n}\n\nfunction normalizeObject(object, targetSize = 1) {\n  object.updateMatrixWorld(true);\n  const box = new THREE.Box3().setFromObject(object);\n  if (box.isEmpty()) return;\n  const center = new THREE.Vector3();\n  const size = new THREE.Vector3();\n  box.getCenter(center);\n  box.getSize(size);\n  object.position.x -= center.x;\n  object.position.z -= center.z;\n  object.position.y -= box.min.y;\n  const maxDim = Math.max(size.x, size.y, size.z);\n  if (maxDim > 0) object.scale.setScalar(targetSize / maxDim);\n}\n\nfunction resize() {\n  const rect = $(\"roomCanvas\").getBoundingClientRect();\n  const w = Math.max(1, rect.width | 0);\n  const h = Math.max(1, rect.height | 0);\n  renderer.setSize(w, h, false);\n  camera.aspect = w / h;\n  camera.updateProjectionMatrix();\n}\n\nfunction animate() {\n  requestAnimationFrame(animate);\n  const now = performance.now();\n  const dt = Math.min(0.05, (now - lastFrame) / 1000);\n  lastFrame = now;\n  orbit.update();\n  updatePlayer(dt);\n  renderer.render(scene, camera);\n}\n\nfunction cleanPath(file, base) {\n  const f = String(file || \"\").replace(/\\\\/g, \"/\").replace(/^\\.\\//, \"\");\n  if (/^(file|https?):/i.test(f)) return f;\n  if (f.startsWith(\"src/assets/\")) return \"./assets/\" + f.slice(\"src/assets/\".length);\n  if (f.startsWith(\"assets/\")) return \"./\" + f;\n  if (f.startsWith(base + \"/\")) return \"./assets/\" + f;\n  return \"./assets/\" + base + \"/\" + f;\n}\n\nasync function loadCatalog() {\n  const list = [];\n  try {\n    const remote = await api()?.listCatalog?.();\n    if (remote?.ok && Array.isArray(remote.items)) list.push(...remote.items);\n  } catch {}\n\n  if (!list.length) {\n    for (const [url, base, category] of [\n      [\"./assets/item_manifest.json\", \"items\", \"furniture\"],\n      [\"./assets/motion_manifest.json\", \"motions\", \"motion\"],\n      [\"./assets/expressions/manifest.json\", \"expressions\", \"expression\"]\n    ]) {\n      try {\n        const data = await (await fetch(url)).json();\n        const arr = Array.isArray(data) ? data : Array.isArray(data.items) ? data.items : Array.isArray(data.motions) ? data.motions : Array.isArray(data.expressions) ? data.expressions : [];\n        arr.forEach((item) => list.push({ ...item, base, category }));\n      } catch {}\n    }\n  }\n\n  catalog = list.map((item, index) => {\n    const id = item.id || item.name || item.label || (\"item_\" + index);\n    const file = item.file || item.path || item.url || \"\";\n    const hay = `${id} ${file} ${item.category || \"\"}`.toLowerCase();\n    const category = item.category || (hay.includes(\"tablet\") || hay.includes(\"phone\") || hay.includes(\"monitor\") ? \"electronics\" : hay.includes(\"table\") || hay.includes(\"desk\") || hay.includes(\"piano\") || hay.includes(\"chair\") ? \"furniture\" : hay.includes(\".vrm\") ? \"avatar\" : \"decor\");\n    return { id: String(id), label: item.label || item.title || String(id), file, category, base: item.base || \"items\", raw: item };\n  }).filter((item) => item.file || item.category === \"avatar\");\n  renderCatalog();\n}\n\nfunction renderCatalog() {\n  const list = $(\"assetList\");\n  if (!list) return;\n  const q = ($(\"assetSearch\").value || \"\").toLowerCase();\n  const filter = $(\"assetFilter\").value || \"all\";\n  list.innerHTML = \"\";\n  catalog.filter((item) => {\n    const okFilter = filter === \"all\" || item.category === filter;\n    const okSearch = !q || `${item.id} ${item.label} ${item.file} ${item.category}`.toLowerCase().includes(q);\n    return okFilter && okSearch;\n  }).slice(0, 180).forEach((item) => {\n    const card = document.createElement(\"article\");\n    card.className = \"item-card\";\n    card.innerHTML = `<strong>${escapeHtml(item.label)}</strong><small>${escapeHtml(item.file || item.category)}</small><button>Adicionar</button>`;\n    card.querySelector(\"button\").onclick = () => addCatalogItem(item);\n    list.appendChild(card);\n  });\n}\n\nasync function addCatalogItem(item) {\n  if (item.category === \"motion\" || item.category === \"expression\") {\n    toast(\"Este item é de avatar; use a janela principal para aplicar.\");\n    return;\n  }\n  const loader = new GLTFLoader();\n  const url = cleanPath(item.file, item.base || \"items\");\n  let object;\n  try {\n    object = (await loader.loadAsync(url)).scene;\n  } catch (err) {\n    object = new THREE.Mesh(new THREE.BoxGeometry(.5,.5,.5), new THREE.MeshStandardMaterial({ color: 0x7a1f35 }));\n    object.userData.loadError = String(err?.message || err);\n  }\n  const wrap = new THREE.Group();\n  wrap.name = \"room:\" + item.id;\n  wrap.add(object);\n  normalizeObject(wrap, item.category === \"furniture\" ? 1.1 : .6);\n  wrap.position.set(0, 0, 0);\n  wrap.userData.roomItem = item;\n  wrap.traverse((child) => {\n    if (child.isMesh) {\n      child.castShadow = true;\n      child.receiveShadow = true;\n      child.frustumCulled = false;\n    }\n  });\n  roomRoot.add(wrap);\n  const uid = item.id + \"_\" + Date.now().toString(36);\n  placed.set(uid, wrap);\n  wrap.userData.uid = uid;\n  selectObject(wrap);\n  commitHistory();\n  toast(\"Adicionado: \" + item.label);\n}\n\nfunction selectObject(object) {\n  selected = object || null;\n  if (selected && mode === \"build\") transform.attach(selected);\n  else transform.detach();\n  renderSelected();\n}\n\nfunction renderSelected() {\n  const box = $(\"selectedBox\");\n  if (!box) return;\n  if (!selected) {\n    box.textContent = \"Nenhum objeto selecionado.\";\n    return;\n  }\n  const p = selected.position;\n  box.innerHTML = `<b>${escapeHtml(selected.name || \"Objeto\")}</b><br>X ${p.x.toFixed(2)} · Y ${p.y.toFixed(2)} · Z ${p.z.toFixed(2)}`;\n}\n\nfunction pickObject(event) {\n  if (mode !== \"build\" || transform.dragging) return;\n  const rect = renderer.domElement.getBoundingClientRect();\n  const mouse = new THREE.Vector2(((event.clientX - rect.left) / rect.width) * 2 - 1, -((event.clientY - rect.top) / rect.height) * 2 + 1);\n  const ray = new THREE.Raycaster();\n  ray.setFromCamera(mouse, camera);\n  const hits = ray.intersectObjects([...placed.values()], true);\n  if (!hits.length) return;\n  let obj = hits[0].object;\n  while (obj && !obj.userData?.uid) obj = obj.parent;\n  if (obj) selectObject(obj);\n}\n\nfunction stopFocus() {\n  if (mode === \"build\") {\n    selectObject(null);\n    orbit.target.set(0, .8, 0);\n    camera.position.set(4.5, 3.2, 5.2);\n    toast(\"Foco no objeto desligado\");\n  } else {\n    requestPointer();\n    toast(\"Movimento livre ativo\");\n  }\n}\n\nfunction updatePlayer(dt) {\n  if (mode === \"build\") return;\n  const speed = keys.has(\"shift\") ? playerState.runSpeed : playerState.speed;\n  const fwd = new THREE.Vector3(Math.sin(playerState.yaw), 0, -Math.cos(playerState.yaw));\n  const right = new THREE.Vector3(Math.cos(playerState.yaw), 0, Math.sin(playerState.yaw));\n  const dir = new THREE.Vector3();\n  if (keys.has(\"w\")) dir.add(fwd);\n  if (keys.has(\"s\")) dir.sub(fwd);\n  if (keys.has(\"d\")) dir.add(right);\n  if (keys.has(\"a\")) dir.sub(right);\n  if (dir.lengthSq()) playerState.pos.add(dir.normalize().multiplyScalar(speed * dt));\n\n  if (!playerState.grounded || playerState.pos.y > 0.001) {\n    playerState.velocityY -= 10.5 * dt;\n    playerState.pos.y += playerState.velocityY * dt;\n    if (playerState.pos.y <= 0) {\n      playerState.pos.y = 0;\n      playerState.velocityY = 0;\n      playerState.grounded = true;\n    }\n  }\n\n  player.position.copy(playerState.pos);\n  player.rotation.y = playerState.yaw;\n  if (mode === \"pov\") {\n    camera.position.set(playerState.pos.x, playerState.pos.y + playerState.eyeHeight, playerState.pos.z);\n    camera.rotation.order = \"YXZ\";\n    camera.rotation.y = playerState.yaw;\n    camera.rotation.x = playerState.pitch;\n  } else {\n    const target = playerState.pos.clone().add(new THREE.Vector3(0, 1.18, 0));\n    const desired = target.clone().add(fwd.clone().multiplyScalar(-3.2)).add(new THREE.Vector3(0, 1.4, 0));\n    camera.position.copy(desired);\n    camera.lookAt(target);\n  }\n  $(\"downPlayer\").textContent = `Yoru: ${playerState.pos.x.toFixed(1)}, ${playerState.pos.y.toFixed(1)}, ${playerState.pos.z.toFixed(1)}`;\n}\n\nfunction jump() {\n  if (mode === \"build\") {\n    toast(\"Pulo funciona em Yoru POV ou Third Person\");\n    return;\n  }\n  if (!playerState.grounded) return;\n  playerState.velocityY = 4.25;\n  playerState.grounded = false;\n  toast(\"Pular\");\n}\n\nfunction requestPointer() {\n  try { renderer.domElement.requestPointerLock?.(); } catch {}\n}\n\nfunction unlockPointer() {\n  try { if (document.pointerLockElement === renderer.domElement) document.exitPointerLock?.(); } catch {}\n}\n\nfunction serializeLayout() {\n  const items = [...placed.entries()].map(([uid, obj]) => ({\n    uid,\n    itemId: obj.userData.roomItem?.id || uid,\n    position: [obj.position.x, obj.position.y, obj.position.z],\n    rotationDeg: [obj.rotation.x, obj.rotation.y, obj.rotation.z].map(THREE.MathUtils.radToDeg),\n    scale: [obj.scale.x, obj.scale.y, obj.scale.z],\n    file: obj.userData.roomItem?.file || \"\"\n  }));\n  return { version: 19, player: { position: [playerState.pos.x, playerState.pos.y, playerState.pos.z], yaw: playerState.yaw, pitch: playerState.pitch }, items };\n}\n\nasync function saveLayout() {\n  const layout = serializeLayout();\n  try {\n    const result = await api()?.saveLayout?.(layout);\n    if (result?.ok) toast(\"Layout salvo\");\n    else throw new Error(\"IPC indisponível\");\n  } catch {\n    localStorage.setItem(\"noelle_room_v19_layout\", JSON.stringify(layout));\n    toast(\"Layout salvo local\");\n  }\n}\n\nasync function loadLayout() {\n  let layout = null;\n  try {\n    const result = await api()?.loadLayout?.();\n    if (result?.ok) layout = result.layout;\n  } catch {}\n  if (!layout) {\n    try { layout = JSON.parse(localStorage.getItem(\"noelle_room_v19_layout\") || \"null\"); } catch {}\n  }\n  if (!layout) return toast(\"Nenhum layout salvo\");\n  clearRoom();\n  if (Array.isArray(layout.items)) {\n    for (const entry of layout.items) {\n      const item = catalog.find((x) => x.id === entry.itemId) || { id: entry.itemId, label: entry.itemId, file: entry.file, category: \"decor\", base: \"items\" };\n      await addCatalogItem(item);\n      if (selected) {\n        selected.position.set(...(entry.position || [0,0,0]));\n        selected.rotation.set(...(entry.rotationDeg || [0,0,0]).map(THREE.MathUtils.degToRad));\n      }\n    }\n  }\n  if (layout.player?.position) playerState.pos.set(...layout.player.position);\n  playerState.yaw = layout.player?.yaw || 0;\n  playerState.pitch = layout.player?.pitch || 0;\n  selectObject(null);\n  toast(\"Layout carregado\");\n}\n\nfunction clearRoom() {\n  for (const obj of placed.values()) obj.removeFromParent();\n  placed.clear();\n  selectObject(null);\n}\n\nfunction commitHistory() {\n  const snap = JSON.stringify(serializeLayout());\n  history = history.slice(0, historyIndex + 1);\n  history.push(snap);\n  if (history.length > 60) history.shift();\n  historyIndex = history.length - 1;\n}\n\nfunction scheduleAutosave() {\n  clearTimeout(scheduleAutosave._t);\n  scheduleAutosave._t = setTimeout(() => {\n    localStorage.setItem(\"noelle_room_v19_autosave\", JSON.stringify(serializeLayout()));\n    $(\"downSave\").textContent = \"Autosave: \" + new Date().toLocaleTimeString(\"pt-BR\");\n  }, 700);\n}\n\nfunction recoverAutosave() {\n  try {\n    const raw = localStorage.getItem(\"noelle_room_v19_autosave\");\n    if (!raw) return toast(\"Sem autosave\");\n    localStorage.setItem(\"noelle_room_v19_layout\", raw);\n    loadLayout();\n  } catch {\n    toast(\"Autosave falhou\");\n  }\n}\n\nfunction renderRoadmap() {\n  const list = $(\"roadmapList\");\n  const q = ($(\"roadmapSearch\").value || \"\").toLowerCase();\n  list.innerHTML = \"\";\n  ROADMAP.forEach((text, idx) => {\n    if (q && !text.toLowerCase().includes(q) && !String(idx+1).includes(q)) return;\n    const card = document.createElement(\"article\");\n    card.className = \"roadmap-card\";\n    card.innerHTML = `<strong>#${idx+1}</strong><small>${escapeHtml(text)}</small>`;\n    list.appendChild(card);\n  });\n}\n\nfunction bindUI() {\n  $(\"modeBuild\").onclick = () => setMode(\"build\");\n  $(\"modePov\").onclick = () => setMode(\"pov\");\n  $(\"modeThird\").onclick = () => setMode(\"third\");\n  $(\"btnJump\").onclick = jump;\n  $(\"btnFreeMove\").onclick = stopFocus;\n  $(\"toolResetPlayer\").onclick = () => { playerState.pos.set(0,0,2.6); playerState.yaw = 0; playerState.pitch = 0; toast(\"Yoru resetada\"); };\n  $(\"toolDefaultCamera\").onclick = stopFocus;\n  $(\"btnSave\").onclick = saveLayout;\n  $(\"btnLoad\").onclick = loadLayout;\n  $(\"btnRecover\").onclick = recoverAutosave;\n  $(\"toolMove\").onclick = () => transform.setMode(\"translate\");\n  $(\"toolRotate\").onclick = () => transform.setMode(\"rotate\");\n  $(\"toolScale\").onclick = () => transform.setMode(\"scale\");\n  $(\"toolGrid\").onclick = () => toast(\"Grid ativo\");\n  $(\"toolUndo\").onclick = () => toast(\"Undo estrutural pronto para consolidar\");\n  $(\"toolRedo\").onclick = () => toast(\"Redo estrutural pronto para consolidar\");\n  $(\"btnDuplicate\").onclick = () => selected ? duplicateSelected() : toast(\"Nenhum item\");\n  $(\"btnLock\").onclick = () => selected ? (selected.userData.locked = !selected.userData.locked, toast(selected.userData.locked ? \"Travado\" : \"Destravado\")) : toast(\"Nenhum item\");\n  $(\"btnGround\").onclick = () => selected ? (selected.position.y = 0, renderSelected(), scheduleAutosave()) : toast(\"Nenhum item\");\n  $(\"btnRemove\").onclick = () => { if (!selected) return toast(\"Nenhum item\"); selected.removeFromParent(); placed.delete(selected.userData.uid); selectObject(null); scheduleAutosave(); };\n  $(\"assetSearch\").oninput = renderCatalog;\n  $(\"assetFilter\").onchange = renderCatalog;\n  $(\"roadmapSearch\").oninput = renderRoadmap;\n\n  window.addEventListener(\"keydown\", (e) => {\n    const k = e.key.toLowerCase();\n    if ([\"input\",\"textarea\",\"select\"].includes(e.target?.tagName?.toLowerCase())) return;\n    if (mode !== \"build\") {\n      if ([\"w\",\"a\",\"s\",\"d\",\"shift\"].includes(k)) keys.add(k);\n      if (e.code === \"Space\") { e.preventDefault(); jump(); }\n    }\n    if (e.ctrlKey && k === \"s\") { e.preventDefault(); saveLayout(); }\n    if (k === \"escape\") unlockPointer();\n  });\n  window.addEventListener(\"keyup\", (e) => keys.delete(e.key.toLowerCase()));\n  window.addEventListener(\"mousemove\", (e) => {\n    pointerLocked = document.pointerLockElement === renderer.domElement;\n    if (mode === \"build\" || !pointerLocked) return;\n    playerState.yaw -= e.movementX * 0.0022;\n    playerState.pitch = Math.max(-1.18, Math.min(1.18, playerState.pitch - e.movementY * 0.0022));\n  });\n  window.addEventListener(\"blur\", () => { keys.clear(); unlockPointer(); });\n}\n\nfunction duplicateSelected() {\n  const clone = selected.clone(true);\n  clone.position.x += .5;\n  clone.position.z += .5;\n  const uid = (selected.userData.roomItem?.id || \"clone\") + \"_\" + Date.now().toString(36);\n  clone.userData = { ...selected.userData, uid };\n  roomRoot.add(clone);\n  placed.set(uid, clone);\n  selectObject(clone);\n  scheduleAutosave();\n}\n\nfunction escapeHtml(value) {\n  const div = document.createElement(\"div\");\n  div.textContent = String(value ?? \"\");\n  return div.innerHTML;\n}\n\nasync function boot() {\n  initScene();\n  bindUI();\n  renderRoadmap();\n  await loadCatalog();\n  await loadYoruPlayer();\n  setMode(\"build\");\n  status(\"Room V19 pronta\", \"ok\");\n  commitHistory();\n}\n\nwindow.addEventListener(\"DOMContentLoaded\", boot);\n", "roadmap_md": "# Noelle V19 — Roadmap 100 melhorias\n\nEste arquivo consolida as 100 sugestões discutidas para a Room/Yoru, sem lotar a UI principal.\n\n1. Confirmar que a Yoru aparece como player real no Third Person, não apenas fallback.\n2. Diagnóstico visual dentro da Room mostrando VRM carregado, fallback, erro de asset e caminho usado.\n3. Melhorar carregamento do Yoru.vrm com log claro de sucesso/falha.\n4. Painel de debug da Room com FPS, modo atual, posição do player, câmera e asset carregado.\n5. Botão Parar foco sempre soltar gizmo e seleção do item.\n6. Evitar conflito ao trocar rápido entre Build Mode, Yoru POV e Third Person.\n7. Câmera Third Person com colisão para não atravessar parede/mesa/piano/objetos grandes.\n8. Ajustar altura dos olhos no Yoru POV por VRM, com fallback configurável.\n9. Botão Recentrar player separado de reset total.\n10. Salvar posição do player corretamente no layout da Room.\n11. Salvar modo atual opcionalmente: Build, Yoru POV ou Third Person.\n12. Melhorar colisão do player com móveis grandes.\n13. Impedir player nascer dentro de objeto depois de carregar layout.\n14. Adicionar chão sólido real para pulo não atravessar ou flutuar.\n15. Melhorar pulo com suavidade, queda natural e limite de spam.\n16. Sistema de paredes da Room em vez de só chão aberto.\n17. Presets reais de quarto: gamer, escritório, musical e simples.\n18. Separar itens de cenário de itens de mão de forma rígida.\n19. Categorias melhores para items: chão, mesa, parede, mão, decoração, eletrônico, instrumento.\n20. Preview do item antes de colocar na Room.\n21. Snap no chão, mesa e parede dependendo do tipo do item.\n22. Pontos de encaixe para mesa: copo, notebook, dado, papel, celular.\n23. Pontos de encaixe para mão/avatar separados da Room.\n24. Impedir item pequeno cair no chão quando deveria ir para mesa.\n25. Botão Mandar para frente da Yoru.\n26. Botão Colocar na mesa mais próxima.\n27. Botão Alinhar com chão melhorado.\n28. Botão Duplicar em grade.\n29. Autosave com várias versões recuperáveis.\n30. Botão Restaurar layout padrão.\n31. Animação idle no Third Person.\n32. Animação walk quando anda.\n33. Animação jump quando pula.\n34. Animação run quando segura Shift.\n35. Sincronizar emotes da Yoru com player da Room.\n36. Sincronizar expressions PNG/VRM com player da Room.\n37. Permitir escolher avatar player: Yoru, Noelle ou outro VRM.\n38. Calibração de altura do avatar.\n39. Opção Mostrar corpo no Yoru POV para debug.\n40. Braços/mãos visíveis no First Person estilo VRChat.\n41. Unificar scripts V18.7, V18.8 e V18.9 para não acumular hotfix.\n42. Criar room_core.js separando player, câmera, layout e UI.\n43. Testes automáticos básicos para Room abrir, bundle gerar e assets existirem.\n44. Diagnóstico para imports de Three.js e @pixiv/three-vrm.\n45. Evitar duplicar handlers de botão quando aplica patch várias vezes.\n46. Garantir só um INICIAR.bat na raiz.\n47. Logs claros no terminal por etapa.\n48. MEMORIA_GPT_NOELLE.md atualizada após cada versão.\n49. Checklist de release: node check, bundle, assets, bat, package, memória.\n50. V19 consolidada limpa, sem restos de hotfix antigo.\n51. Tela Room Status dentro da Room.\n52. Indicador visual do modo atual no canto da tela.\n53. Mini tutorial dentro da Room com controles básicos.\n54. Botão Reset câmera separado do Parar foco.\n55. Reset player mais seguro, voltando para spawn livre.\n56. Spawn point editável para escolher onde a Yoru nasce.\n57. Item invisível Player Spawn no Build Mode.\n58. Proteção contra spawn dentro de parede/móvel.\n59. Sistema de paredes com colisão real.\n60. Teto opcional para Room fechada.\n61. Modo quarto aberto e quarto fechado.\n62. Luz ambiente configurável: claro, escuro, noite, neon, gamer.\n63. Slider de intensidade da luz.\n64. Botão Centralizar Room.\n65. Grid configurável: 0.1, 0.25, 0.5, 1.0.\n66. Snap toggle por eixo: X, Y, Z.\n67. Rotação com snap configurável: 5°, 15°, 30°, 45°, 90°.\n68. Botão Desfazer seleção além do Parar foco.\n69. Outline melhor no item selecionado.\n70. Highlight ao passar mouse sobre item.\n71. Painel de propriedades por item com nome, categoria, posição, rotação, escala e colisão.\n72. Permitir renomear itens colocados na Room.\n73. Permitir travar/destravar item individualmente.\n74. Permitir esconder/mostrar item sem apagar.\n75. Camadas: cenário, móveis, decoração, interativos.\n76. Filtro somente itens visíveis no layout list.\n77. Busca no layout list.\n78. Selecionar item na lista e olhar para ele somente em Build.\n79. Modo câmera livre sem selecionar objeto.\n80. Modo espectador/freecam separado da Yoru POV.\n81. Controle de velocidade da câmera livre.\n82. Controle de velocidade da Yoru.\n83. Controle de altura da câmera do Yoru POV.\n84. Controle de distância da câmera Third Person.\n85. Controle de suavidade da câmera Third Person.\n86. Colisão da câmera com paredes e objetos grandes mais precisa.\n87. Botão Teleportar Yoru para cá clicando no chão.\n88. Botão Trazer Yoru para frente da câmera.\n89. Botão Olhar para item selecionado sem travar foco permanentemente.\n90. Interação básica com objetos: sentar, tocar piano, pegar item, beber água.\n91. Tags de interação no manifesto: sit, drink, play_music, hold, inspect.\n92. Hotspots nos móveis: cadeira tem ponto de sentar, mesa tem ponto de colocar item.\n93. Lógica item de mão + emoção, por exemplo ação de beber usa item correto.\n94. Presets de ação: beber água, usar celular, sentar, tocar piano.\n95. Estados da Yoru por modo: idle, walk, run, jump, sit, interact.\n96. Transição suave entre animações.\n97. Fallback de animação se VRMA não existir.\n98. animation_manifest.json separado ligando animações a ações.\n99. interaction_manifest.json ligando itens a ações possíveis.\n100. V19 como versão consolidada, removendo restos de hotfix e deixando Room/Yoru como sistema principal estável.\n", "build_script": "\"use strict\";\n\nconst fs = require(\"fs\");\nconst path = require(\"path\");\n\nconst ROOT = process.cwd();\n\nasync function main() {\n  let esbuild;\n  try {\n    esbuild = require(\"esbuild\");\n  } catch {\n    console.error(\"[ERRO] esbuild não encontrado. Rode npm install.\");\n    process.exit(1);\n  }\n\n  const entry = path.join(ROOT, \"src\", \"renderer\", \"room_v19_app.js\");\n  const outdir = path.join(ROOT, \"src\", \"renderer_dist\");\n  const outfile = path.join(outdir, \"room.bundle.js\");\n\n  if (!fs.existsSync(entry)) {\n    console.error(\"[ERRO] Entrada da Room V19 não encontrada:\", entry);\n    process.exit(1);\n  }\n\n  fs.mkdirSync(outdir, { recursive: true });\n\n  await esbuild.build({\n    entryPoints: [entry],\n    outfile,\n    bundle: true,\n    format: \"iife\",\n    platform: \"browser\",\n    target: [\"chrome120\"],\n    sourcemap: true,\n    logLevel: \"info\"\n  });\n\n  console.log(\"[OK] Room V19 bundle gerado:\", path.relative(ROOT, outfile));\n}\n\nmain().catch((err) => {\n  console.error(err);\n  process.exit(1);\n});\n", "diag_script": "\"use strict\";\n\nconst fs = require(\"fs\");\nconst path = require(\"path\");\nconst cp = require(\"child_process\");\n\nconst ROOT = process.cwd();\nfunction exists(rel) { return fs.existsSync(path.join(ROOT, rel)); }\nfunction read(rel) { return exists(rel) ? fs.readFileSync(path.join(ROOT, rel), \"utf8\") : \"\"; }\nfunction ok(msg) { console.log(\"[OK] \" + msg); }\nfunction warn(msg) { console.log(\"[AVISO] \" + msg); }\nfunction err(msg) { console.error(\"[ERRO] \" + msg); process.exitCode = 1; }\nfunction checkJs(rel) {\n  if (!exists(rel)) return warn(rel + \" não encontrado.\");\n  const result = cp.spawnSync(process.execPath, [\"--check\", path.join(ROOT, rel)], { encoding: \"utf8\" });\n  if (result.status === 0) ok(\"node --check \" + rel);\n  else { err(\"node --check falhou: \" + rel); console.error(result.stderr || result.stdout); }\n}\nfunction countGlob(dir, re) {\n  try { return fs.readdirSync(path.join(ROOT, dir)).filter((f) => re.test(f)).length; } catch { return 0; }\n}\n\nconsole.log(\"============================================================\");\nconsole.log(\" Diagnóstico V19 MegaLayout 2026\");\nconsole.log(\"============================================================\");\n\nfor (const rel of [\n  \"src/room.html\",\n  \"src/styles/room_v19.css\",\n  \"src/renderer/room_v19_app.js\",\n  \"docs/NOELLE_V19_100_SUGESTOES.md\",\n  \"src/avatar_view.html\",\n  \"src/renderer/avatar_window_app.js\",\n  \"src/renderer/motions.js\",\n  \"src/renderer/items.js\",\n  \"src/renderer/local_assets.js\",\n  \"src/assets/Noelle.vrm\",\n  \"src/assets/motion_manifest.json\",\n  \"src/assets/item_manifest.json\",\n  \"src/assets/expressions/manifest.json\"\n]) {\n  exists(rel) ? ok(rel + \" existe.\") : err(rel + \" faltando.\");\n}\n\ncheckJs(\"main.js\");\ncheckJs(\"preload.js\");\ncheckJs(\"src/renderer/controls_window_app.js\");\ncheckJs(\"src/renderer/room_v19_app.js\");\ncheckJs(\"scripts/build_room_v19_2026.cjs\");\n\nconst html = read(\"src/room.html\");\nif (html.includes(\"room-topbar\") && html.includes(\"room-leftbar\") && html.includes(\"room-rightbar\") && html.includes(\"room-downbar\")) ok(\"Layout anti-sobreposição detectado.\");\nelse err(\"Layout top/left/right/downbar não detectado.\");\n\nconst app = read(\"src/renderer/room_v19_app.js\");\nif (app.includes(\"ROADMAP\") && app.includes(\"Yoru POV\") && app.includes(\"Parar foco\")) ok(\"Room V19 inclui roadmap, Yoru POV e Parar foco.\");\nelse err(\"Room V19 incompleta.\");\n\nconst main = read(\"main.js\");\nif (main.includes(\"NOELLE_ROOM_V19_BEGIN\") && main.includes(\"room:open\")) ok(\"main.js tem Room V19 IPC.\");\nelse err(\"main.js sem Room V19 IPC.\");\n\nconst preload = read(\"preload.js\");\nif (preload.includes(\"noelleRoomV19\")) ok(\"preload expõe noelleRoomV19.\");\nelse err(\"preload sem noelleRoomV19.\");\n\nconst bats = fs.readdirSync(ROOT).filter((f) => /\\.bat$/i.test(f));\nif (bats.length === 1 && bats[0].toLowerCase() === \"iniciar.bat\") ok(\"Apenas INICIAR.bat na raiz.\");\nelse warn(\"BATs na raiz: \" + bats.join(\", \"));\n\nok(\"VRM em avatars: \" + countGlob(\"src/assets/avatars\", /\\.vrm$/i));\nok(\"Motions VRMA: \" + countGlob(\"src/assets/motions\", /\\.vrma$/i));\nok(\"Expressions PNG: \" + countGlob(\"src/assets/expressions\", /\\.png$/i));\nok(\"Items GLB: \" + countGlob(\"src/assets/items\", /\\.(glb|gltf)$/i));\n\nif (exists(\"src/renderer_dist/room.bundle.js\")) ok(\"room.bundle.js existe.\");\nelse warn(\"room.bundle.js ainda não existe; rode npm run build-room.\");\n\nconsole.log(\"============================================================\");\nif (process.exitCode) console.log(\"[RESULTADO] Existem problemas.\");\nelse console.log(\"[RESULTADO] Diagnóstico sem erro crítico.\");\n", "main_block": "// NOELLE_ROOM_V19_BEGIN\nfunction noelleV19RoomLayoutFile() {\n  const dir = path.join(getUserDataSafe(), \"rooms\");\n  ensureDir(dir);\n  return path.join(dir, \"room_v19_layout.json\");\n}\nfunction noelleV19ReadJson(file, fallback) {\n  try {\n    if (!fs.existsSync(file)) return fallback;\n    const text = fs.readFileSync(file, \"utf8\").trim();\n    return text ? JSON.parse(text) : fallback;\n  } catch {\n    return fallback;\n  }\n}\nfunction noelleV19SanitizeLayout(layout) {\n  return {\n    version: Number(layout?.version || 19),\n    player: {\n      position: Array.isArray(layout?.player?.position) ? layout.player.position.slice(0, 3).map(Number) : [0, 0, 2.6],\n      yaw: Number(layout?.player?.yaw || 0),\n      pitch: Number(layout?.player?.pitch || 0)\n    },\n    items: Array.isArray(layout?.items) ? layout.items.slice(0, 500).map((item) => ({\n      uid: String(item.uid || \"\").slice(0, 120),\n      itemId: String(item.itemId || \"\").slice(0, 120),\n      file: String(item.file || \"\").slice(0, 240),\n      position: Array.isArray(item.position) ? item.position.slice(0, 3).map(Number) : [0, 0, 0],\n      rotationDeg: Array.isArray(item.rotationDeg) ? item.rotationDeg.slice(0, 3).map(Number) : [0, 0, 0],\n      scale: Array.isArray(item.scale) ? item.scale.slice(0, 3).map((v) => Math.max(0.001, Number(v) || 1)) : [1, 1, 1]\n    })).filter((item) => item.uid && item.itemId) : []\n  };\n}\nfunction noelleV19Catalog() {\n  const items = [];\n  const itemManifest = noelleV19ReadJson(path.join(ASSETS_DIR, \"item_manifest.json\"), []);\n  const itemList = Array.isArray(itemManifest) ? itemManifest : Array.isArray(itemManifest.items) ? itemManifest.items : [];\n  for (const item of itemList) items.push({ ...item, base: \"items\", category: item.category || \"furniture\" });\n  return items;\n}\nfunction createRoomWindow({ show = true } = {}) {\n  if (roomWin && !roomWin.isDestroyed()) {\n    if (show) roomWin.show();\n    roomWin.focus();\n    return roomWin;\n  }\n  roomWin = new BrowserWindow({\n    width: 1440,\n    height: 900,\n    minWidth: 980,\n    minHeight: 680,\n    title: \"Noelle Room V19\",\n    icon: typeof getAppIconPath === \"function\" ? getAppIconPath() : undefined,\n    backgroundColor: \"#070711\",\n    autoHideMenuBar: true,\n    show: false,\n    webPreferences: {\n      preload: path.join(ROOT_DIR, \"preload.js\"),\n      contextIsolation: true,\n      nodeIntegration: false,\n      sandbox: false\n    }\n  });\n  roomWin.once(\"ready-to-show\", () => { if (show) roomWin.show(); });\n  roomWin.on(\"closed\", () => { roomWin = null; });\n  roomWin.loadFile(path.join(SRC_DIR, \"room.html\"));\n  return roomWin;\n}\ntry { ipcMain.removeHandler(\"room:open\"); } catch {}\ntry { ipcMain.removeHandler(\"room:catalog\"); } catch {}\ntry { ipcMain.removeHandler(\"room:load-layout\"); } catch {}\ntry { ipcMain.removeHandler(\"room:save-layout\"); } catch {}\nipcMain.handle(\"room:open\", async () => { createRoomWindow({ show: true }); return { ok: true }; });\nipcMain.handle(\"room:catalog\", async () => ({ ok: true, items: noelleV19Catalog() }));\nipcMain.handle(\"room:load-layout\", async () => ({ ok: true, layout: noelleV19SanitizeLayout(noelleV19ReadJson(noelleV19RoomLayoutFile(), null)) }));\nipcMain.handle(\"room:save-layout\", async (_event, layout) => {\n  const safe = noelleV19SanitizeLayout(layout || {});\n  const file = noelleV19RoomLayoutFile();\n  const tmp = file + \".tmp\";\n  fs.writeFileSync(tmp, JSON.stringify(safe, null, 2), \"utf8\");\n  fs.renameSync(tmp, file);\n  return { ok: true, layout: safe };\n});\n// NOELLE_ROOM_V19_END\n", "preload_patch": "\n// NOELLE_ROOM_V19_PRELOAD_SAFE_BEGIN\n(() => {\n  try {\n    const electronForNoelleRoomV19 = require(\"electron\");\n    const bridgeForNoelleRoomV19 = electronForNoelleRoomV19.contextBridge;\n    const ipcForNoelleRoomV19 = electronForNoelleRoomV19.ipcRenderer;\n\n    if (!bridgeForNoelleRoomV19 || !ipcForNoelleRoomV19) return;\n    if (globalThis.__NOELLE_ROOM_V19_PRELOAD_EXPOSED__) return;\n\n    globalThis.__NOELLE_ROOM_V19_PRELOAD_EXPOSED__ = true;\n\n    bridgeForNoelleRoomV19.exposeInMainWorld(\"noelleRoomV19\", {\n      open: () => ipcForNoelleRoomV19.invoke(\"room:open\"),\n      listCatalog: () => ipcForNoelleRoomV19.invoke(\"room:catalog\"),\n      loadLayout: () => ipcForNoelleRoomV19.invoke(\"room:load-layout\"),\n      saveLayout: (layout) => ipcForNoelleRoomV19.invoke(\"room:save-layout\", layout)\n    });\n  } catch (err) {\n    try {\n      console.warn(\"[Noelle] noelleRoomV19 preload indisponível\", err);\n    } catch {}\n  }\n})();\n// NOELLE_ROOM_V19_PRELOAD_SAFE_END\n", "controls_launcher_js": "\n(function mountNoelleRoomV19Launcher() {\n  function mount() {\n    if (document.getElementById(\"noelle-room-v19-launcher\")) return;\n    const button = document.createElement(\"button\");\n    button.id = \"noelle-room-v19-launcher\";\n    button.type = \"button\";\n    button.textContent = \"🏠 Room V19\";\n    button.title = \"Abrir Noelle Room V19\";\n    Object.assign(button.style, {\n      position: \"fixed\",\n      right: \"18px\",\n      bottom: \"18px\",\n      zIndex: \"99999\",\n      border: \"1px solid rgba(255,83,136,.55)\",\n      borderRadius: \"999px\",\n      padding: \"11px 16px\",\n      color: \"#fff\",\n      fontWeight: \"900\",\n      background: \"linear-gradient(135deg,#ff477e,#8b5cf6)\",\n      boxShadow: \"0 14px 44px rgba(0,0,0,.35)\",\n      cursor: \"pointer\"\n    });\n    button.addEventListener(\"click\", async () => {\n      try {\n        await (window.noelleRoomV19 || window.noelleRoom)?.open?.();\n      } catch (err) {\n        console.error(\"Falha ao abrir Room V19\", err);\n      }\n    });\n    document.body.appendChild(button);\n  }\n  if (document.readyState === \"loading\") document.addEventListener(\"DOMContentLoaded\", mount);\n  else mount();\n})();\n"};

function abs(rel) { return path.join(ROOT, rel); }
function exists(rel) { return fs.existsSync(abs(rel)); }
function read(rel) { return fs.readFileSync(abs(rel), "utf8"); }
function write(rel, text) { fs.mkdirSync(path.dirname(abs(rel)), { recursive: true }); fs.writeFileSync(abs(rel), text, "utf8"); }
function log(msg) { console.log(msg); }
function warn(msg) { console.log("[AVISO] " + msg); }
function fail(msg) { console.error("[ERRO] " + msg); process.exitCode = 1; }

function backup(rel) {
  if (!exists(rel)) return;
  const dst = path.join(BACKUP_ROOT, rel);
  fs.mkdirSync(path.dirname(dst), { recursive: true });
  fs.copyFileSync(abs(rel), dst);
}

function backupAndWrite(rel, text) {
  backup(rel);
  write(rel, text);
  log("[OK] Atualizado: " + rel);
}

function runCheck(rel) {
  if (!exists(rel)) return true;
  const result = cp.spawnSync(process.execPath, ["--check", abs(rel)], { encoding: "utf8" });
  if (result.status !== 0) {
    console.error(result.stdout || "");
    console.error(result.stderr || "");
    fail("node --check falhou: " + rel);
    return false;
  }
  log("[OK] node --check " + rel);
  return true;
}

function replaceMarked(text, begin, end, block) {
  const re = new RegExp(begin + "[\\s\\S]*?" + end, "g");
  return re.test(text) ? text.replace(re, block) : text + "\n" + block + "\n";
}

function patchMain() {
  const rel = "main.js";
  if (!exists(rel)) return warn("main.js não encontrado; pulando Room IPC.");
  let text = read(rel);
  if (!text.includes("let roomWin")) {
    text = text.replace(/let mainWin\s*=\s*null\s*;/, "let mainWin = null; let roomWin = null;");
  }
  text = replaceMarked(text, "\\/\\/ NOELLE_ROOM_V19_BEGIN", "\\/\\/ NOELLE_ROOM_V19_END", FILES["main_block"]);
  backupAndWrite(rel, text);
}

function patchPreload() {
  const rel = "preload.js";
  if (!exists(rel)) return warn("preload.js não encontrado; pulando noelleRoomV19.");
  let text = read(rel);
  if (!text.includes("noelleRoomV19")) text += "\n" + FILES["preload_patch"] + "\n";
  backupAndWrite(rel, text);
}

function patchControlsLauncher() {
  const rel = "src/renderer/controls_window_app.js";
  if (exists(rel)) {
    let text = read(rel);
    if (!text.includes("noelle-room-v19-launcher")) {
      text += "\n" + FILES["controls_launcher_js"] + "\n";
      backupAndWrite(rel, text);
    } else {
      log("[OK] Launcher Room V19 já existe em controls_window_app.js");
    }
  } else {
    warn("src/renderer/controls_window_app.js não encontrado.");
  }

  const htmlRel = "src/controls.html";
  if (exists(htmlRel)) {
    let html = read(htmlRel);
    if (!html.includes("noelle-room-v19-launcher-inline")) {
      const inline = `<button id="noelle-room-v19-launcher-inline" style="position:fixed;right:18px;bottom:72px;z-index:99999;border:1px solid rgba(255,83,136,.55);border-radius:999px;padding:11px 16px;color:#fff;font-weight:900;background:linear-gradient(135deg,#ff477e,#8b5cf6);box-shadow:0 14px 44px rgba(0,0,0,.35);cursor:pointer">🏠 Room V19</button><script>document.getElementById("noelle-room-v19-launcher-inline")?.addEventListener("click",()=>{(window.noelleRoomV19||window.noelleRoom)?.open?.()})</script>`;
      if (html.includes("</body>")) html = html.replace("</body>", inline + "\n</body>");
      else html += "\n" + inline + "\n";
      backupAndWrite(htmlRel, html);
    }
  }
}

function patchPackage() {
  const rel = "package.json";
  if (!exists(rel)) return warn("package.json não encontrado.");
  let pkg;
  try { pkg = JSON.parse(read(rel)); } catch (err) { return warn("package.json inválido: " + err.message); }
  backup(rel);
  pkg.version = "19.0.0-megalayout-2026";
  pkg.scripts = {
    ...(pkg.scripts || {}),
    "build-room": "node scripts/build_room_v19_2026.cjs",
    "diagnostico-room": "node scripts/diagnostico_room_v19_2026.cjs",
    "diagnostico:v19": "node scripts/diagnostico_room_v19_2026.cjs"
  };
  pkg.dependencies = { ...(pkg.dependencies || {}) };
  if (!pkg.dependencies.three) pkg.dependencies.three = "0.184.0";
  if (!pkg.dependencies["@pixiv/three-vrm"]) pkg.dependencies["@pixiv/three-vrm"] = "3.5.2";
  pkg.devDependencies = { ...(pkg.devDependencies || {}) };
  if (!pkg.devDependencies.esbuild) pkg.devDependencies.esbuild = "0.28.0";
  write(rel, JSON.stringify(pkg, null, 2) + "\n");
  log("[OK] package.json atualizado sem trocar Electron agressivamente.");
}

function patchMemory() {
  const rel = "MEMORIA_GPT_NOELLE.md";
  if (!exists(rel)) return warn("MEMORIA_GPT_NOELLE.md não encontrado.");
  let text = read(rel);
  if (!text.includes("V19 MegaLayout 2026")) {
    text += `\n\n## V19 MegaLayout 2026\n\n- Room passa a usar layout anti-sobreposição: topbar, leftbar, viewport central, rightbar e downbar.\n- As 100 sugestões ficam em docs/NOELLE_V19_100_SUGESTOES.md e também aparecem no painel Roadmap 100 da Room.\n- O botão Room V19 é adicionado sem remover a janela principal antiga.\n- Avatar/widget, Chat IA, Emotes, Expressions e Inventário continuam preservados.\n- V19 cria uma Room separada em src/room.html e renderer próprio src/renderer/room_v19_app.js.\n`;
    backupAndWrite(rel, text);
  }
}

function apply() {
  fs.mkdirSync(BACKUP_ROOT, { recursive: true });
  log("[INFO] Backup em: " + BACKUP_ROOT);

  backupAndWrite("src/room.html", FILES["room_html"]);
  backupAndWrite("src/styles/room_v19.css", FILES["room_css"]);
  backupAndWrite("src/renderer/room_v19_app.js", FILES["room_app"]);
  backupAndWrite("docs/NOELLE_V19_100_SUGESTOES.md", FILES["roadmap_md"]);
  backupAndWrite("scripts/build_room_v19_2026.cjs", FILES["build_script"]);
  backupAndWrite("scripts/diagnostico_room_v19_2026.cjs", FILES["diag_script"]);

  patchMain();
  patchPreload();
  patchControlsLauncher();
  patchPackage();
  patchMemory();

  for (const rel of [
    "main.js",
    "preload.js",
    "src/renderer/controls_window_app.js",
    "src/renderer/room_v19_app.js",
    "scripts/build_room_v19_2026.cjs",
    "scripts/diagnostico_room_v19_2026.cjs"
  ]) runCheck(rel);

  log("");
  log("[OK] V19 MegaLayout 2026 aplicada.");
  log("[INFO] Próximo passo: node scripts/build_room_v19_2026.cjs");
}

if (process.argv.includes("--apply")) apply();
else console.log("Uso: node scripts/apply_v19_megalayout_2026.cjs --apply");
